// Helper functions

// detectLockfileType detects the type of a lockfile based on its name
func detectLockfileType(filepath string) ftypes.TargetType {
	filename := extractFilename(filepath)

	switch filename {
	case "pnpm-lock.yaml":
		return ftypes.PnpmLock
	case "package-lock.json":
		return ftypes.Npm
	case "yarn.lock":
		return ftypes.Yarn
	case "packages.lock.json", "project.assets.json":
		return ftypes.NuGet
	case ".csproj", ".vbproj":
		return ftypes.DotNetCore
	default:
		return ftypes.Unknown
	}
}

// extractFilename extracts just the filename from a full path
func extractFilename(filepath string) string {
	return path_filename(filepath)
}

func path_filename(path string) string {
	for i := len(path) - 1; i >= 0; i-- {
		if path[i] == '/' || path[i] == '\\' {
			return path[i+1:]
		}
	}
	return path
}

// analyzeLibraryFile attempts to analyze a library file using Trivy's fanal analyzer
func analyzeLibraryFile(filePath string, contents []byte) (*analysisResult, error) {
	// This simulates what AnalyzeLibrary does in scanner/base.go
	// For the regression test, we'll do a simplified version that shows where issues would occur

	info, err := os.Stat(filePath)
	if err != nil {
		return nil, xerrors.Errorf("Failed to stat file: %w", err)
	}

	// Simulate analyzer initialization with language-specific analyzers only
	// In the buggy version, this might include OS analyzers, secrets, licenses, etc.

	// For now, just verify the file can be read
	data, err := os.ReadFile(filePath)
	if err != nil {
		return nil, xerrors.Errorf("Failed to read file: %w", err)
	}

	if !bytes.Equal(data, contents) {
		return nil, xerrors.New("File contents mismatch")
	}

	// Return empty result with expected structure
	// In a real scenario, this would be populated by Trivy analyzers
	return &analysisResult{
		Applications: []application{},
	}, nil
}

// Mock structures for testing
type analysisResult struct {
	Applications []application
}

type application struct {
	Type     ftypes.TargetType
	FilePath string
	Packages []packageInfo
}

type packageInfo struct {
	Name    string
	Version string
}

// TestDBClientAPIIncompatibility documents the known Trivy DB client API change
func TestDBClientAPIIncompatibility(t *testing.T) {
	// Trivy v0.69.1 changed the db.NewClient signature
	//
	// OLD signature (used by vuls detector/library.go:133):
	//   client := db.NewClient(path, noProgress, db.WithDBRepository(refs))
	//
	// EXPECTED signature in v0.69.1:
	//   client := db.NewClient(path, noProgress, db.WithDBRepository(refs), registryOpts)
	//   or possibly: client := db.NewClient(path, noProgress, opts)
	//
	// The actual signature requires checking Trivy v0.69.1 source, but the bug
	// is that vuls doesn't provide all required parameters.

	// Create a minimal test to show the failure would occur
	tempDir := t.TempDir()

	// Try the old vuls signature - this should fail compilation or at runtime
	// Uncomment this to see the actual error:
	/*
	refs := make([]name.Reference, 0)
	client := db.NewClient(filepath.Join(tempDir, "db"), false, db.WithDBRepository(refs))
	// If we get here, the API changed but vuls wasn't updated
	if client == nil {
		t.Error("Failed to create DB client - API incompatibility with Trivy v0.69.1")
	}
	*/

	// For now, document the failure mode
	t.Logf("Test documents that db.NewClient API is incompatible with Trivy v0.69.1")
	t.Logf("Error would be: missing required parameter or wrong signature")
}

// TestMissingPackageEcosystems tests that PNPM and .NET ecosystems
// produce zero vulnerability findings despite known vulnerable packages
func TestMissingPackageEcosystems(t *testing.T) {
	// Scenario 1: PNPM lockfile with known vulnerable package
	pnpmWithVulnContent := `lockfileVersion: '9.0'
importers:
  .:
    dependencies:
      lodash:
        specifier: '^4.17.0'
        version: 4.17.15  # This version has known vulnerabilities
packages:
  /lodash@4.17.15:
    resolution: {integrity: sha512-8Z1K+H4XEsCzC+jUar87zKfEC3ETwPVEZH/8AyXvUmvCGoVLn3aFo82n3DvMEfzqIDm29qCgsf9QtcUquufrHA==}
`

	tempDir := t.TempDir()
	pnpmFile := filepath.Join(tempDir, "pnpm-lock.yaml")
	if err := os.WriteFile(pnpmFile, []byte(pnpmWithVulnContent), 0644); err != nil {
		t.Fatalf("Failed to create pnpm test file: %v", err)
	}

	// When scanning this, we should find vulnerabilities for lodash 4.17.15
	// Bug: Due to missing ecosystem support, we get 0 vulnerabilities

	result, err := analyzeLibraryFile(pnpmFile, []byte(pnpmWithVulnContent))
	if err != nil {
		t.Logf("Analysis failed: %v", err)
		return
	}

	if result == nil || len(result.Applications) == 0 {
		t.Logf("REGRESSION: PNPM ecosystem not detected - expected to find 'lodash' package but got 0 applications")
	}

	// Scenario 2: .NET with vulnerable package
	dotnetContent := `<Project Sdk="Microsoft.NET.Sdk">
  <ItemGroup>
    <PackageReference Include="System.Net.Http" Version="4.3.0" />
  </ItemGroup>
</Project>
`

	dotnetFile := filepath.Join(tempDir, "Vulnerable.csproj")
	if err := os.WriteFile(dotnetFile, []byte(dotnetContent), 0644); err != nil {
		t.Fatalf("Failed to create dotnet test file: %v", err)
	}

	result, err = analyzeLibraryFile(dotnetFile, []byte(dotnetContent))
	if err != nil {
		t.Logf("Analysis failed: %v", err)
		return
	}

	if result == nil || len(result.Applications) == 0 {
		t.Logf("REGRESSION: .NET ecosystem not detected - expected to find packages but got 0 applications")
	}
}

package main

import (
	"bytes"
	"encoding/json"
	"os"
