33: // DefaultTrivyDBRepositories is the official repositories of Trivy DB
34: var DefaultTrivyDBRepositories = []string{db.DefaultGCRRepository, db.DefaultGHCRRepository}
35: 
36: type libraryDetector struct {
37: 	scanner               models.LibraryScanner
38: 	javaDBClient          *javadb.DBClient
39: 	detectDevDependencies bool
40: }
