42: // DetectLibsCves fills LibraryScanner information
43: func DetectLibsCves(r *models.ScanResult, trivyOpts config.TrivyOpts, logOpts logging.LogOpts, noProgress bool) (err error) {
44: 	totalCnt := 0
45: 	if len(r.LibraryScanners) == 0 {
46: 		return
47: 	}
48: 
49: 	// initialize trivy's logger and db
50: 	log.InitLogger(logOpts.Debug, logOpts.Quiet)
51: 
52: 	logging.Log.Info("Updating library db...")
53: 	if err := downloadDB("", trivyOpts, noProgress, false); err != nil {
54: 		return xerrors.Errorf("Failed to download trivy DB. err: %w", err)
55: 	}
56: 	if err := trivydb.Init(filepath.Join(trivyOpts.TrivyCacheDBDir, "db")); err != nil {
57: 		return xerrors.Errorf("Failed to init trivy DB. err: %w", err)
58: 	}
59: 	defer trivydb.Close()
60: 
61: 	var javaDBClient *javadb.DBClient
62: 	defer javaDBClient.Close()
63: 	for i, lib := range r.LibraryScanners {
64: 		d := libraryDetector{
65: 			scanner:               lib,
66: 			detectDevDependencies: slices.Contains(trivyOpts.DetectDevLockfilePaths, lib.LockfilePath),
67: 		}
68: 		if lib.Type == ftypes.Jar {
69: 			if javaDBClient == nil {
70: 				if err := javadb.UpdateJavaDB(trivyOpts, noProgress); err != nil {
71: 					return xerrors.Errorf("Failed to update Trivy Java DB. err: %w", err)
72: 				}
73: 
74: 				javaDBClient, err = javadb.NewClient(trivyOpts.TrivyCacheDBDir)
75: 				if err != nil {
76: 					return xerrors.Errorf("Failed to open Trivy Java DB. err: %w", err)
77: 				}
78: 			}
79: 			d.javaDBClient = javaDBClient
80: 		}
81: 
82: 		vinfos, err := d.scan()
83: 		if err != nil {
84: 			return xerrors.Errorf("Failed to scan library. err: %w", err)
85: 		}
86: 		r.LibraryScanners[i] = d.scanner
87: 		for _, vinfo := range vinfos {
88: 			vinfo.Confidences.AppendIfMissing(models.TrivyMatch)
89: 			if v, ok := r.ScannedCves[vinfo.CveID]; !ok {
90: 				r.ScannedCves[vinfo.CveID] = vinfo
91: 			} else {
92: 				v.LibraryFixedIns = append(v.LibraryFixedIns, vinfo.LibraryFixedIns...)
93: 				r.ScannedCves[vinfo.CveID] = v
94: 			}
95: 		}
96: 		totalCnt += len(vinfos)
97: 	}
98: 
99: 	logging.Log.Infof("%s: %d CVEs are detected with Library",
100: 		r.FormatServerName(), totalCnt)
101: 
102: 	return nil
103: }
