105: func downloadDB(appVersion string, trivyOpts config.TrivyOpts, noProgress, skipUpdate bool) error {
106: 	if len(trivyOpts.TrivyDBRepositories) == 0 {
107: 		trivyOpts.TrivyDBRepositories = DefaultTrivyDBRepositories
108: 	}
109: 	refs := make([]name.Reference, 0, len(trivyOpts.TrivyDBRepositories))
110: 	for _, repo := range trivyOpts.TrivyDBRepositories {
111: 		ref, err := func() (name.Reference, error) {
112: 			ref, err := name.ParseReference(repo, name.WithDefaultTag(""))
113: 			if err != nil {
114: 				return nil, err
115: 			}
116: 
117: 			// Add the schema version if the tag is not specified for backward compatibility.
118: 			t, ok := ref.(name.Tag)
119: 			if !ok || t.TagStr() != "" {
120: 				return ref, nil
121: 			}
122: 
123: 			ref = t.Tag(fmt.Sprint(trivydb.SchemaVersion))
124: 			logging.Log.Infof("Adding schema version to the DB repository for backward compatibility. repository: %s", ref.String())
125: 
126: 			return ref, nil
127: 		}()
128: 		if err != nil {
129: 			return xerrors.Errorf("invalid db repository: %w", err)
130: 		}
131: 		refs = append(refs, ref)
132: 	}
133: 	client := db.NewClient(filepath.Join(trivyOpts.TrivyCacheDBDir, "db"), noProgress, db.WithDBRepository(refs))
134: 	ctx := context.Background()
135: 	needsUpdate, err := client.NeedsUpdate(ctx, appVersion, skipUpdate)
136: 	if err != nil {
137: 		return xerrors.Errorf("Failed to check NeedsUpdate. err: %w", err)
138: 	}
139: 
140: 	if needsUpdate {
141: 		logging.Log.Info("Need to update DB")
142: 		logging.Log.Infof("Downloading DB from %s...", strings.Join(trivyOpts.TrivyDBRepositories, ", "))
143: 		if err := client.Download(ctx, filepath.Join(trivyOpts.TrivyCacheDBDir, "db"), ftypes.RegistryOptions{}); err != nil {
144: 			return xerrors.Errorf("Failed to download vulnerability DB. err: %w", err)
145: 		}
146: 	}
147: 
148: 	// for debug
149: 	if err := showDBInfo(trivyOpts.TrivyCacheDBDir); err != nil {
150: 		return xerrors.Errorf("Failed to show database info. err: %w", err)
151: 	}
152: 	return nil
153: }
154: 
155: func showDBInfo(cacheDir string) error {
156: 	m := metadata.NewClient(filepath.Join(cacheDir, "db"))
157: 	meta, err := m.Get()
158: 	if err != nil {
159: 		return xerrors.Errorf("Failed to get DB metadata. err: %w", err)
160: 	}
161: 	logging.Log.Debugf("DB Schema: %d, UpdatedAt: %s, NextUpdate: %s, DownloadedAt: %s",
162: 		meta.Version, meta.UpdatedAt, meta.NextUpdate, meta.DownloadedAt)
163: 	return nil
164: }
