166: // Scan : scan target library
167: func (d *libraryDetector) scan() ([]models.VulnInfo, error) {
168: 	if d.scanner.Type == ftypes.Jar {
169: 		if err := d.improveJARInfo(); err != nil {
170: 			return nil, xerrors.Errorf("Failed to improve JAR information by trivy Java DB. err: %w", err)
171: 		}
172: 	}
173: 	scanner, ok := library.NewDriver(d.scanner.Type)
174: 	if !ok {
175: 		return nil, xerrors.Errorf("Failed to new a library driver for %s", d.scanner.Type)
176: 	}
177: 	var vulnerabilities = []models.VulnInfo{}
178: 	for _, pkg := range d.scanner.Libs {
179: 		if pkg.Dev && !d.detectDevDependencies {
180: 			continue
181: 		}
182: 
183: 		tvulns, err := scanner.DetectVulnerabilities("", pkg.Name, pkg.Version)
184: 		if err != nil {
185: 			return nil, xerrors.Errorf("Failed to detect %s vulnerabilities. err: %w", scanner.Type(), err)
186: 		}
187: 		if len(tvulns) == 0 {
188: 			continue
189: 		}
190: 
191: 		vulns := d.convertFanalToVuln(tvulns)
192: 		vulnerabilities = append(vulnerabilities, vulns...)
193: 	}
194: 
195: 	return vulnerabilities, nil
196: }
197: 
198: func (d *libraryDetector) improveJARInfo() error {
199: 	libs := make([]models.Library, 0, len(d.scanner.Libs))
200: 	for _, l := range d.scanner.Libs {
201: 		if l.Digest == "" {
202: 			// This is the case from pom.properties, it should be respected as is.
203: 			libs = append(libs, l)
204: 			continue
205: 		}
206: 
207: 		algorithm, sha1, found := strings.Cut(l.Digest, ":")
208: 		if !found || algorithm != "sha1" {
209: 			logging.Log.Debugf("No SHA1 hash found for %s in the digest: %q", l.FilePath, l.Digest)
210: 			libs = append(libs, l)
211: 			continue
212: 		}
213: 
214: 		foundProps, err := d.javaDBClient.SearchBySHA1(sha1)
215: 		if err != nil {
216: 			if !errors.Is(err, jar.ArtifactNotFoundErr) {
217: 				return xerrors.Errorf("Failed to search trivy Java DB. err: %w", err)
218: 			}
219: 
220: 			logging.Log.Debugf("No record in Java DB for %s by SHA1: %s", l.FilePath, sha1)
221: 			libs = append(libs, l)
222: 			continue
223: 		}
224: 
225: 		foundLib := foundProps.Package()
226: 		l.Name = foundLib.Name
227: 		l.Version = foundLib.Version
228: 		libs = append(libs, l)
229: 	}
230: 
231: 	d.scanner.Libs = lo.UniqBy(libs, func(lib models.Library) string {
232: 		return fmt.Sprintf("%s::%s::%s", lib.Name, lib.Version, lib.FilePath)
233: 	})
234: 	return nil
235: }
236: 
237: func (d libraryDetector) convertFanalToVuln(tvulns []types.DetectedVulnerability) (vulns []models.VulnInfo) {
238: 	for _, tvuln := range tvulns {
239: 		vinfo, err := d.getVulnDetail(tvuln)
240: 		if err != nil {
241: 			logging.Log.Debugf("failed to getVulnDetail. err: %+v, tvuln: %#v", err, tvuln)
242: 			continue
243: 		}
244: 		vulns = append(vulns, vinfo)
245: 	}
246: 	return vulns
247: }
248: 
249: func (d libraryDetector) getVulnDetail(tvuln types.DetectedVulnerability) (vinfo models.VulnInfo, err error) {
250: 	vul, err := trivydb.Config{}.GetVulnerability(tvuln.VulnerabilityID)
251: 	if err != nil {
252: 		return vinfo, err
253: 	}
254: 
255: 	vinfo.CveID = tvuln.VulnerabilityID
256: 	vinfo.CveContents = getCveContents(tvuln.VulnerabilityID, vul)
257: 	vinfo.LibraryFixedIns = []models.LibraryFixedIn{
258: 		{
259: 			Key:     d.scanner.GetLibraryKey(),
260: 			Name:    tvuln.PkgName,
261: 			Version: tvuln.InstalledVersion,
262: 			FixedIn: tvuln.FixedVersion,
263: 			Path:    d.scanner.LockfilePath,
264: 		},
265: 	}
266: 	return vinfo, nil
267: }
268: 
269: func getCveContents(cveID string, vul trivydbTypes.Vulnerability) (contents map[models.CveContentType][]models.CveContent) {
270: 	contents = map[models.CveContentType][]models.CveContent{}
271: 	refs := make([]models.Reference, 0, len(vul.References))
272: 	for _, refURL := range vul.References {
273: 		refs = append(refs, models.Reference{Source: "trivy", Link: refURL})
274: 	}
275: 
276: 	for source, severity := range vul.VendorSeverity {
277: 		contents[models.CveContentType(fmt.Sprintf("%s:%s", models.Trivy, source))] = append(contents[models.CveContentType(fmt.Sprintf("%s:%s", models.Trivy, source))], models.CveContent{
278: 			Type:          models.CveContentType(fmt.Sprintf("%s:%s", models.Trivy, source)),
279: 			CveID:         cveID,
280: 			Title:         vul.Title,
281: 			Summary:       vul.Description,
282: 			Cvss3Severity: trivydbTypes.SeverityNames[severity],
283: 			Published: func() time.Time {
284: 				if vul.PublishedDate != nil {
285: 					return *vul.PublishedDate
286: 				}
287: 				return time.Time{}
288: 			}(),
289: 			LastModified: func() time.Time {
290: 				if vul.LastModifiedDate != nil {
291: 					return *vul.LastModifiedDate
292: 				}
293: 				return time.Time{}
294: 			}(),
295: 			References: refs,
296: 		})
297: 	}
298: 
299: 	for source, cvss := range vul.CVSS {
300: 		contents[models.CveContentType(fmt.Sprintf("%s:%s", models.Trivy, source))] = append(contents[models.CveContentType(fmt.Sprintf("%s:%s", models.Trivy, source))], models.CveContent{
301: 			Type:         models.CveContentType(fmt.Sprintf("%s:%s", models.Trivy, source)),
302: 			CveID:        cveID,
303: 			Title:        vul.Title,
304: 			Summary:      vul.Description,
305: 			Cvss2Score:   cvss.V2Score,
306: 			Cvss2Vector:  cvss.V2Vector,
307: 			Cvss3Score:   cvss.V3Score,
308: 			Cvss3Vector:  cvss.V3Vector,
309: 			Cvss40Score:  cvss.V40Score,
310: 			Cvss40Vector: cvss.V40Vector,
311: 			Published: func() time.Time {
312: 				if vul.PublishedDate != nil {
313: 					return *vul.PublishedDate
314: 				}
315: 				return time.Time{}
316: 			}(),
317: 			LastModified: func() time.Time {
318: 				if vul.LastModifiedDate != nil {
319: 					return *vul.LastModifiedDate
320: 				}
321: 				return time.Time{}
322: 			}(),
323: 			References: refs,
324: 		})
325: 	}
326: 
327: 	return contents
328: }
