146: func (l *base) runningKernel() (release, version string, err error) {
147: 	r := l.exec("uname -r", noSudo)
148: 	if !r.isSuccess() {
149: 		return "", "", xerrors.Errorf("Failed to SSH: %s", r)
150: 	}
151: 	release = strings.TrimSpace(r.Stdout)
152: 
153: 	switch l.Distro.Family {
154: 	case constant.Debian:
155: 		r := l.exec(fmt.Sprintf("dpkg-query -W -f='${Version}' linux-image-%s", release), noSudo)
156: 		if !r.isSuccess() {
157: 			l.log.Debugf("Failed to get the running kernel version. err: %s", r.Stderr)
158: 			return release, "", nil
159: 		}
160: 		return release, r.Stdout, nil
161: 	default:
162: 		return release, "", nil
163: 	}
164: }
