271: func (l *base) parseDockerPs(stdout string) (containers []config.Container, err error) {
272: 	lines := strings.SplitSeq(stdout, "\n")
273: 	for line := range lines {
274: 		fields := strings.Fields(line)
275: 		if len(fields) == 0 {
276: 			break
277: 		}
278: 		if len(fields) != 3 {
279: 			return containers, xerrors.Errorf("Unknown format: %s", line)
280: 		}
281: 		containers = append(containers, config.Container{
282: 			ContainerID: fields[0],
283: 			Name:        fields[1],
284: 			Image:       fields[2],
285: 		})
286: 	}
287: 	return
288: }
289: 
290: func (l *base) parseLxdPs(stdout string) (containers []config.Container, err error) {
291: 	lines := strings.Split(stdout, "\n")
292: 	for i, line := range lines[3:] {
293: 		if i%2 == 1 {
294: 			continue
295: 		}
296: 		fields := strings.Fields(strings.ReplaceAll(line, "|", " "))
297: 		if len(fields) == 0 {
298: 			break
299: 		}
300: 		if len(fields) != 1 {
301: 			return containers, xerrors.Errorf("Unknown format: %s", line)
302: 		}
303: 		containers = append(containers, config.Container{
304: 			ContainerID: fields[0],
305: 			Name:        fields[0],
306: 		})
307: 	}
308: 	return
309: }
