326: // ip executes ip command and returns IP addresses
327: func (l *base) ip() ([]string, []string, error) {
328: 	// e.g.
329: 	// 2: eth0: <BROADCAST,MULTICAST,UP,LOWER_UP> mtu 1500 qdisc pfifo_fast state UP qlen 1000\    link/ether 52:54:00:2a:86:4c brd ff:ff:ff:ff:ff:ff
330: 	// 2: eth0    inet 10.0.2.15/24 brd 10.0.2.255 scope global eth0
331: 	// 2: eth0    inet6 fe80::5054:ff:fe2a:864c/64 scope link \       valid_lft forever preferred_lft forever
332: 	r := l.exec("/sbin/ip -o addr", noSudo)
333: 	if !r.isSuccess() {
334: 		return nil, nil, xerrors.Errorf("Failed to detect IP address: %v", r)
335: 	}
336: 	ipv4Addrs, ipv6Addrs := l.parseIP(r.Stdout)
337: 	return ipv4Addrs, ipv6Addrs, nil
338: }
339: 
340: // parseIP parses the results of ip command
341: func (l *base) parseIP(stdout string) (ipv4Addrs []string, ipv6Addrs []string) {
342: 	lines := strings.SplitSeq(stdout, "\n")
343: 	for line := range lines {
344: 		fields := strings.Fields(line)
345: 		if len(fields) < 4 {
346: 			continue
347: 		}
348: 		ip, _, err := net.ParseCIDR(fields[3])
349: 		if err != nil {
350: 			continue
351: 		}
352: 		if !ip.IsGlobalUnicast() {
353: 			continue
354: 		}
355: 		if ipv4 := ip.To4(); ipv4 != nil {
356: 			ipv4Addrs = append(ipv4Addrs, ipv4.String())
357: 		} else {
358: 			ipv6Addrs = append(ipv6Addrs, ip.String())
359: 		}
360: 	}
361: 	return
362: }
363: 
364: // parseIfconfig parses the results of ifconfig command
365: func (l *base) parseIfconfig(stdout string) (ipv4Addrs []string, ipv6Addrs []string) {
366: 	lines := strings.SplitSeq(stdout, "\n")
367: 	for line := range lines {
368: 		line = strings.TrimSpace(line)
369: 		fields := strings.Fields(line)
370: 		if len(fields) < 4 || !strings.HasPrefix(fields[0], "inet") {
371: 			continue
372: 		}
373: 		ip := net.ParseIP(fields[1])
374: 		if ip == nil {
375: 			continue
376: 		}
377: 		if !ip.IsGlobalUnicast() {
378: 			continue
379: 		}
380: 		if ipv4 := ip.To4(); ipv4 != nil {
381: 			ipv4Addrs = append(ipv4Addrs, ipv4.String())
382: 		} else {
383: 			ipv6Addrs = append(ipv6Addrs, ip.String())
384: 		}
385: 	}
386: 	return
387: }
