413: func (l *base) detectDeepSecurity() (string, error) {
414: 	// only work root user
415: 	if l.getServerInfo().Mode.IsFastRoot() {
416: 		if r := l.exec("test -f /opt/ds_agent/dsa_query", sudo); r.isSuccess() {
417: 			cmd := fmt.Sprintf(`/opt/ds_agent/dsa_query -c "GetAgentStatus" | grep %q`, dsFingerPrintPrefix)
418: 			r := l.exec(cmd, sudo)
419: 			if r.isSuccess() {
420: 				line := strings.TrimSpace(r.Stdout)
421: 				return line[len(dsFingerPrintPrefix):], nil
422: 			}
423: 			l.warns = append(l.warns, xerrors.New("Fail to retrieve deepsecurity fingerprint"))
424: 		}
425: 	}
426: 	return "", xerrors.Errorf("Failed to detect deepsecurity %s", l.ServerInfo.ServerName)
427: }
