439: func (l *base) detectRunningOnAws() (ok bool, instanceID string, err error) {
440: 	if r := l.exec("type curl", noSudo); r.isSuccess() {
441: 		cmd := "curl --max-time 1 --noproxy 169.254.169.254 http://169.254.169.254/latest/meta-data/instance-id"
442: 		r := l.exec(cmd, noSudo)
443: 		if r.isSuccess() {
444: 			id := strings.TrimSpace(r.Stdout)
445: 			if l.isAwsInstanceID(id) {
446: 				return true, id, nil
447: 			}
448: 		}
449: 
450: 		cmd = "curl -X PUT --max-time 1 --noproxy 169.254.169.254 -H \"X-aws-ec2-metadata-token-ttl-seconds: 300\" http://169.254.169.254/latest/api/token"
451: 		r = l.exec(cmd, noSudo)
452: 		if r.isSuccess() {
453: 			token := strings.TrimSpace(r.Stdout)
454: 			cmd = fmt.Sprintf("curl -H \"X-aws-ec2-metadata-token: %s\" --max-time 1 --noproxy 169.254.169.254 http://169.254.169.254/latest/meta-data/instance-id", token)
455: 			r = l.exec(cmd, noSudo)
456: 			if r.isSuccess() {
457: 				id := strings.TrimSpace(r.Stdout)
458: 				if !l.isAwsInstanceID(id) {
459: 					return false, "", nil
460: 				}
461: 				return true, id, nil
462: 			}
463: 		}
464: 
465: 		switch r.ExitStatus {
466: 		case 28, 7:
467: 			// Not running on AWS
468: 			//  7   Failed to connect to host.
469: 			// 28  operation timeout.
470: 			return false, "", nil
471: 		}
472: 	}
473: 
474: 	if r := l.exec("type wget", noSudo); r.isSuccess() {
475: 		cmd := "wget --tries=3 --timeout=1 --no-proxy -q -O - http://169.254.169.254/latest/meta-data/instance-id"
476: 		r := l.exec(cmd, noSudo)
477: 		if r.isSuccess() {
478: 			id := strings.TrimSpace(r.Stdout)
479: 			if !l.isAwsInstanceID(id) {
480: 				return false, "", nil
481: 			}
482: 			return true, id, nil
483: 		}
484: 
485: 		switch r.ExitStatus {
486: 		case 4, 8:
487: 			// Not running on AWS
488: 			// 4   Network failure
489: 			// 8   Server issued an error response.
490: 			return false, "", nil
491: 		}
492: 	}
493: 	return false, "", xerrors.Errorf(
494: 		"Failed to curl or wget to AWS instance metadata on %s. container: %s",
495: 		l.ServerInfo.ServerName, l.ServerInfo.Container.Name)
496: }
