505: func (l *base) convertToModel() models.ScanResult {
506: 	ctype := l.ServerInfo.ContainerType
507: 	if l.ServerInfo.Container.ContainerID != "" && ctype == "" {
508: 		ctype = "docker"
509: 	}
510: 	container := models.Container{
511: 		ContainerID: l.ServerInfo.Container.ContainerID,
512: 		Name:        l.ServerInfo.Container.Name,
513: 		Image:       l.ServerInfo.Container.Image,
514: 		Type:        ctype,
515: 	}
516: 
517: 	errs, warns := make([]string, 0, len(l.errs)), make([]string, 0, len(l.warns))
518: 	for _, e := range l.errs {
519: 		errs = append(errs, fmt.Sprintf("%+v", e))
520: 	}
521: 	for _, w := range l.warns {
522: 		warns = append(warns, fmt.Sprintf("%+v", w))
523: 	}
524: 
525: 	scannedVia := scannedViaRemote
526: 	if isLocalExec(l.ServerInfo.Port, l.ServerInfo.Host) {
527: 		scannedVia = scannedViaLocal
528: 	} else if l.ServerInfo.Type == constant.ServerTypePseudo {
529: 		scannedVia = scannedViaPseudo
530: 	}
531: 
532: 	return models.ScanResult{
533: 		JSONVersion:       models.JSONVersion,
534: 		ServerName:        l.ServerInfo.ServerName,
535: 		ScannedAt:         time.Now(),
536: 		ScanMode:          l.ServerInfo.Mode.String(),
537: 		Family:            l.Distro.Family,
538: 		Release:           l.Distro.Release,
539: 		Container:         container,
540: 		Platform:          l.Platform,
541: 		IPv4Addrs:         l.ServerInfo.IPv4Addrs,
542: 		IPv6Addrs:         l.ServerInfo.IPv6Addrs,
543: 		IPSIdentifiers:    l.ServerInfo.IPSIdentifiers,
544: 		ScannedCves:       l.VulnInfos,
545: 		ScannedVia:        scannedVia,
546: 		RunningKernel:     l.Kernel,
547: 		Packages:          l.Packages,
548: 		SrcPackages:       l.SrcPackages,
549: 		WordPressPackages: l.WordPress,
550: 		LibraryScanners:   l.LibraryScanners,
551: 		WindowsKB:         l.windowsKB,
552: 		Optional:          l.ServerInfo.Optional,
553: 		Errors:            errs,
554: 		Warnings:          warns,
555: 	}
556: }
