577: func (l *base) detectInitSystem() (string, error) {
578: 	var f func(string) (string, error)
579: 	f = func(cmd string) (string, error) {
580: 		r := l.exec(cmd, sudo)
581: 		if !r.isSuccess() {
582: 			return "", xerrors.Errorf("Failed to stat %s: %s", cmd, r)
583: 		}
584: 		scanner := bufio.NewScanner(strings.NewReader(r.Stdout))
585: 		scanner.Scan()
586: 		line := strings.TrimSpace(scanner.Text())
587: 		if strings.Contains(line, "systemd") {
588: 			return systemd, nil
589: 		} else if strings.Contains(line, "upstart") {
590: 			return upstart, nil
591: 		} else if strings.Contains(line, "File: ‘/proc/1/exe’ -> ‘/sbin/init’") ||
592: 			strings.Contains(line, "File: `/proc/1/exe' -> `/sbin/init'") {
593: 			return f("stat /sbin/init")
594: 		} else if line == "File: ‘/sbin/init’" ||
595: 			line == "File: `/sbin/init'" {
596: 			r := l.exec("/sbin/init --version", noSudo)
597: 			if r.isSuccess() {
598: 				if strings.Contains(r.Stdout, "upstart") {
599: 					return upstart, nil
600: 				}
601: 			}
602: 			return sysVinit, nil
603: 		}
604: 		return "", xerrors.Errorf("Failed to detect a init system: %s", line)
605: 	}
606: 	return f("stat /proc/1/exe")
607: }
