631: func (l *base) scanLibraries() (err error) {
632: 	if len(l.LibraryScanners) > 0 {
633: 		return nil
634: 	}
635: 
636: 	// library scan for servers need lockfiles
637: 	if len(l.ServerInfo.Lockfiles) == 0 && !l.ServerInfo.FindLock {
638: 		return nil
639: 	}
640: 
641: 	l.log.Info("Scanning Language-specific Packages...")
642: 
643: 	trivyLoggerInit()
644: 
645: 	detectFiles := l.ServerInfo.Lockfiles
646: 
647: 	priv := noSudo
648: 	if l.getServerInfo().Mode.IsFastRoot() || l.getServerInfo().Mode.IsDeep() {
649: 		priv = sudo
650: 	}
651: 
652: 	// auto detect lockfile
653: 	if l.ServerInfo.FindLock {
654: 		dir := func() string {
655: 			if len(l.ServerInfo.FindLockDirs) == 0 {
656: 				l.log.Infof("It's recommended to specify FindLockDirs in config.toml. If FindLockDirs is not specified, all directories under / will be searched, which may increase CPU load")
657: 				return "/"
658: 			}
659: 			return strings.Join(l.ServerInfo.FindLockDirs, " ")
660: 		}()
661: 
662: 		findopt := func() string {
663: 			ss := make([]string, 0, len(models.FindLockFiles))
664: 			for _, filename := range models.FindLockFiles {
665: 				ss = append(ss, fmt.Sprintf("-name %q", filename))
666: 			}
667: 			return strings.Join(ss, " -o ")
668: 		}()
669: 
670: 		l.log.Infof("Finding files under %s", dir)
671: 
672: 		// find / -type f -and \( -name "package-lock.json" -o -name "yarn.lock" ... \) 2>&1 | grep -v "find: "
673: 		r := l.exec(fmt.Sprintf(`find %s -type f -and \( %s \) 2>&1 | grep -v "find: "`, dir, findopt), priv)
674: 		if r.ExitStatus != 0 && r.ExitStatus != 1 {
675: 			return xerrors.Errorf("Failed to find lock files: %s", r)
676: 		}
677: 
678: 		scanner := bufio.NewScanner(strings.NewReader(r.Stdout))
679: 		for scanner.Scan() {
680: 			detectFiles = append(detectFiles, scanner.Text())
681: 		}
682: 		if err := scanner.Err(); err != nil {
683: 			return xerrors.Errorf("Failed to reading find results. err: %w", err)
684: 		}
685: 	}
686: 
687: 	found := make(map[string]bool)
688: 	for _, path := range detectFiles {
689: 		if path == "" {
690: 			continue
691: 		}
692: 
693: 		abspath, err := func() (string, error) {
694: 			if ufilepath.IsAbs(path) {
695: 				return ufilepath.Clean(path), nil
696: 			}
697: 
698: 			r := l.exec("pwd", noSudo)
699: 			if !r.isSuccess() {
700: 				return "", xerrors.Errorf("Failed to get current directory. err: %w", r.Error)
701: 			}
702: 
703: 			return ufilepath.Join(strings.TrimSuffix(r.Stdout, "\n"), path), nil
704: 		}()
705: 		if err != nil {
706: 			return xerrors.Errorf("Failed to abs the lockfile. filepath: %s, err: %w", path, err)
707: 		}
708: 
709: 		if _, ok := found[abspath]; ok {
710: 			continue
711: 		}
712: 		found[abspath] = true
713: 
714: 		l.log.Debugf("Analyzing file: %s", abspath)
715: 		filemode, contents, err := func() (os.FileMode, []byte, error) {
716: 			r := l.exec(fmt.Sprintf(`stat -c "%%a" %s`, abspath), priv)
717: 			if !r.isSuccess() {
718: 				return os.FileMode(0000), nil, xerrors.Errorf("Failed to get target file permission. filepath: %s, err: %w", abspath, err)
719: 			}
720: 			permStr := fmt.Sprintf("0%s", strings.TrimSuffix(r.Stdout, "\n"))
721: 			perm, err := strconv.ParseUint(permStr, 8, 32)
722: 			if err != nil {
723: 				return os.FileMode(0000), nil, xerrors.Errorf("Failed to parse permission string. , permission string: %s, err: %s", permStr, err)
724: 			}
725: 			filemode := os.FileMode(perm)
726: 
727: 			r = l.exec(fmt.Sprintf("cat %s", abspath), priv)
728: 			if !r.isSuccess() {
729: 				return os.FileMode(0000), nil, xerrors.Errorf("Failed to read target file contents. filepath: %s, err: %w", abspath, err)
730: 			}
731: 			contents := []byte(r.Stdout)
732: 
733: 			return filemode, contents, nil
734: 		}()
735: 		if err != nil {
736: 			l.log.Warn(err)
737: 			continue
738: 		}
739: 
740: 		libraryScanners, err := AnalyzeLibrary(context.Background(), abspath, contents, filemode, l.ServerInfo.Mode.IsOffline())
741: 		if err != nil {
742: 			return xerrors.Errorf("Failed to analyze library. err: %w, filepath: %s", err, abspath)
743: 		}
744: 		for _, libscanner := range libraryScanners {
745: 			libscanner.LockfilePath = abspath
746: 			l.LibraryScanners = append(l.LibraryScanners, libscanner)
747: 		}
748: 	}
749: 	return nil
750: }
