752: // AnalyzeLibrary : detects library defined in artifact such as lockfile or jar
753: func AnalyzeLibrary(ctx context.Context, path string, contents []byte, filemode os.FileMode, isOffline bool) (libraryScanners []models.LibraryScanner, err error) {
754: 	ag, err := fanal.NewAnalyzerGroup(fanal.AnalyzerOptions{
755: 		Group:             fanal.GroupBuiltin,
756: 		DisabledAnalyzers: disabledAnalyzers,
757: 	})
758: 	if err != nil {
759: 		return nil, xerrors.Errorf("Failed to new analyzer group. err: %w", err)
760: 	}
761: 
762: 	// `errgroup` cancels the context after Wait returns, so it can’t be use later.
763: 	// We need a separate context specifically for Analyze.
764: 	eg, egCtx := errgroup.WithContext(ctx)
765: 	result := fanal.NewAnalysisResult()
766: 
767: 	info := &DummyFileInfo{name: ufilepath.Base(path), size: int64(len(contents)), filemode: filemode}
768: 	opts := fanal.AnalysisOptions{Offline: isOffline}
769: 	if err := ag.AnalyzeFile(
770: 		egCtx,
771: 		eg,
772: 		semaphore.New(1),
773: 		result,
774: 		"",
775: 		path,
776: 		info,
777: 		func() (xio.ReadSeekCloserAt, error) { return xio.NopCloser(bytes.NewReader(contents)), nil },
778: 		nil,
779: 		opts,
780: 	); err != nil {
781: 		return nil, xerrors.Errorf("Failed to get libs. err: %w", err)
782: 	}
783: 
784: 	if err := eg.Wait(); err != nil {
785: 		return nil, xerrors.Errorf("analyze error: %w", err)
786: 	}
787: 
788: 	// Post-analysis
789: 	composite, err := ag.PostAnalyzerFS()
790: 	if err != nil {
791: 		return nil, xerrors.Errorf("Failed to prepare filesystem for post-analysis. err: %w", err)
792: 	}
793: 	defer func() {
794: 		_ = composite.Cleanup()
795: 	}()
796: 
797: 	analyzerTypes := ag.RequiredPostAnalyzers(path, info)
798: 	if len(analyzerTypes) != 0 {
799: 		opener := func() (xio.ReadSeekCloserAt, error) { return xio.NopCloser(bytes.NewReader(contents)), nil }
800: 		tmpFilePath, err := composite.CopyFileToTemp(opener, info)
801: 		if err != nil {
802: 			return nil, xerrors.Errorf("Failed to copy file to temp. err: %w", err)
803: 		}
804: 		if err := composite.CreateLink(analyzerTypes, "", path, tmpFilePath); err != nil {
805: 			return nil, xerrors.Errorf("Failed to create link. err: %w", err)
806: 		}
807: 		if err = ag.PostAnalyze(ctx, composite, result, opts); err != nil {
808: 			return nil, xerrors.Errorf("Failed at post-analysis. err: %w", err)
809: 		}
810: 	}
811: 
812: 	libscan, err := convertLibWithScanner(result.Applications)
813: 	if err != nil {
814: 		return nil, xerrors.Errorf("Failed to convert libs. err: %w", err)
815: 	}
816: 	libraryScanners = append(libraryScanners, libscan...)
817: 	return libraryScanners, nil
818: }
