920: func (l *base) buildWpCliCmd(wpCliArgs string, suppressStderr bool, shell string) string {
921: 	cmd := fmt.Sprintf("%s %s --path=%s", l.ServerInfo.WordPress.CmdPath, wpCliArgs, l.ServerInfo.WordPress.DocRoot)
922: 	if !l.ServerInfo.WordPress.NoSudo {
923: 		cmd = fmt.Sprintf("sudo -u %s -i -- %s --allow-root", l.ServerInfo.WordPress.OSUser, cmd)
924: 	} else if l.ServerInfo.User != l.ServerInfo.WordPress.OSUser {
925: 		cmd = fmt.Sprintf("su %s -c '%s'", l.ServerInfo.WordPress.OSUser, cmd)
926: 	}
927: 
928: 	if suppressStderr {
929: 		switch shell {
930: 		case "csh", "tcsh":
931: 			cmd = fmt.Sprintf("( %s > /dev/tty ) >& /dev/null", cmd)
932: 		default:
933: 			cmd = fmt.Sprintf("%s 2>/dev/null", cmd)
934: 		}
935: 	}
936: 	return cmd
937: }
