969: func (l *base) detectShell() (string, error) {
970: 	if r := l.exec("printenv SHELL", noSudo); r.isSuccess() {
971: 		if t := strings.TrimSpace(r.Stdout); t != "" {
972: 			return filepath.Base(t), nil
973: 		}
974: 	}
975: 
976: 	if r := l.exec(fmt.Sprintf(`grep "^%s" /etc/passwd | awk -F: '/%s/ { print $7 }'`, l.ServerInfo.User, l.ServerInfo.User), noSudo); r.isSuccess() {
977: 		if t := strings.TrimSpace(r.Stdout); t != "" {
978: 			return filepath.Base(t), nil
979: 		}
980: 	}
981: 
982: 	if isLocalExec(l.ServerInfo.Port, l.ServerInfo.Host) {
983: 		if r := l.exec("ps -p $$ | tail +2 | awk '{print $NF}'", noSudo); r.isSuccess() {
984: 			return strings.TrimSpace(r.Stdout), nil
985: 		}
986: 
987: 		if r := l.exec("ps -p %self | tail +2 | awk '{print $NF}'", noSudo); r.isSuccess() {
988: 			return strings.TrimSpace(r.Stdout), nil
989: 		}
990: 	}
991: 
992: 	return "", xerrors.New("shell cannot be determined")
993: }
