1080: func (l *base) detectScanDest() map[string][]string {
1081: 	scanIPPortsMap := map[string][]string{}
1082: 
1083: 	for _, p := range l.Packages {
1084: 		if p.AffectedProcs == nil {
1085: 			continue
1086: 		}
1087: 		for _, proc := range p.AffectedProcs {
1088: 			if proc.ListenPortStats == nil {
1089: 				continue
1090: 			}
1091: 			for _, port := range proc.ListenPortStats {
1092: 				scanIPPortsMap[port.BindAddress] = append(scanIPPortsMap[port.BindAddress], port.Port)
1093: 			}
1094: 		}
1095: 	}
1096: 
1097: 	scanDestIPPorts := map[string][]string{}
1098: 	for addr, ports := range scanIPPortsMap {
1099: 		if addr == "*" {
1100: 			for _, addr := range l.ServerInfo.IPv4Addrs {
1101: 				scanDestIPPorts[addr] = append(scanDestIPPorts[addr], ports...)
1102: 			}
1103: 		} else {
1104: 			scanDestIPPorts[addr] = append(scanDestIPPorts[addr], ports...)
1105: 		}
1106: 	}
1107: 
1108: 	uniqScanDestIPPorts := map[string][]string{}
1109: 	for i, scanDest := range scanDestIPPorts {
1110: 		m := map[string]bool{}
1111: 		for _, e := range scanDest {
1112: 			if !m[e] {
1113: 				m[e] = true
1114: 				uniqScanDestIPPorts[i] = append(uniqScanDestIPPorts[i], e)
1115: 			}
1116: 		}
1117: 	}
1118: 
1119: 	return uniqScanDestIPPorts
1120: }
