1122: func (l *base) execPortsScan(scanDestIPPorts map[string][]string) ([]string, error) {
1123: 	if l.getServerInfo().PortScan.IsUseExternalScanner {
1124: 		listenIPPorts, err := l.execExternalPortScan(scanDestIPPorts)
1125: 		if err != nil {
1126: 			return []string{}, err
1127: 		}
1128: 		return listenIPPorts, nil
1129: 	}
1130: 
1131: 	listenIPPorts, err := l.execNativePortScan(scanDestIPPorts)
