package main

import (
	"bytes"
	"context"
	"os"
	"path/filepath"
	"testing"

	ftypes "github.com/aquasecurity/trivy/pkg/fanal/types"
	"github.com/aquasecurity/trivy/pkg/db"
	"github.com/google/go-containerregistry/pkg/name"
	"golang.org/x/xerrors"
)

// TestTrivyDBClientInitializationFailure tests that the Trivy DB client
// initialization fails due to missing required parameters in the current Trivy v0.69.1 API.
//
// The issue: The Trivy API at v0.69.1 has added a required parameter to db.NewClient,
// but vuls code at line 133 of detector/library.go still uses the old signature:
//   client := db.NewClient(filepath.Join(trivyOpts.TrivyCacheDBDir, "db"), noProgress, db.WithDBRepository(refs))
//
// The new signature in Trivy v0.69.1 requires a RegistryOptions parameter.
func TestTrivyDBClientInitializationFailure(t *testing.T) {
	tempDir := t.TempDir()
	dbPath := filepath.Join(tempDir, "db")

	// Create empty db directory structure that Trivy expects
	if err := os.MkdirAll(dbPath, 0755); err != nil {
		t.Fatalf("Failed to create temp db directory: %v", err)
	}

	// Try to create a client with the current vuls signature
	// This should fail with a compilation error or runtime panic
	// because Trivy v0.69.1 expects additional parameters
	refs := make([]name.Reference, 0)

	// This call will fail - demonstrates the API incompatibility
	// The old code tries: db.NewClient(path, noProgress, db.WithDBRepository(refs))
	// But Trivy v0.69.1 may require: db.NewClient(path, noProgress, db.WithDBRepository(refs), registryOpts)
	//
	// We attempt the old-style call and verify it fails
	_ = db.NewClient(dbPath, false, db.WithDBRepository(refs))

	// If we reach here without panic, the test should document that the API changed
	// and the old signature is no longer compatible
	t.Logf("WARNING: db.NewClient call succeeded, but may not have the correct signature for Trivy v0.69.1")
}

// TestPnpmLockfileNotSupported tests that PNPM lockfiles are not recognized
// during library scanning. The scanner imports the pnpm analyzer but may not
// properly register it, or the type detection fails.
func TestPnpmLockfileNotSupported(t *testing.T) {
	pnpmLockContent := `lockfileVersion: '9.0'
importers:
  .:
    dependencies:
      lodash:
        specifier: ^4.17.21
        version: 4.17.21
packages:
  /lodash@4.17.21:
    resolution: {integrity: sha512-v2kDEe57lecTulaDIuNTPy3Ry4gLGuDNyLvp3uyF7FSMvqe+1/0npjrC0T8lNydQrVZ8sk+F3l1d9fV7lvstwg==}
`

	// Simulate lockfile analysis
	tempDir := t.TempDir()
	pnpmLockFile := filepath.Join(tempDir, "pnpm-lock.yaml")

	if err := os.WriteFile(pnpmLockFile, []byte(pnpmLockContent), 0644); err != nil {
		t.Fatalf("Failed to write pnpm-lock.yaml: %v", err)
	}

	// Try to detect the lockfile type
	// The expected behavior: The type should be detected as ftypes.PnpmLock
	// The actual behavior (buggy): Type detection may fail or analyzer may not work

	lockfileType := detectLockfileType(pnpmLockFile)

	if lockfileType != ftypes.PnpmLock {
		t.Errorf("Expected lockfile type %v, got %v for pnpm-lock.yaml", ftypes.PnpmLock, lockfileType)
	}

	// Further test: verify that the pnpm analyzer can parse this file
	// This is where the regression would manifest - the analyzer registered but not working
	result, err := analyzeLibraryFile(pnpmLockFile, []byte(pnpmLockContent))
	if err != nil {
		t.Errorf("Failed to analyze pnpm-lock.yaml: %v", err)
	}

	if result == nil || len(result.Applications) == 0 {
		t.Error("Expected to find packages in pnpm-lock.yaml analysis, but got none")
	}
}

// TestDotNetDependenciesNotSupported tests that .NET dependency files are not
// properly recognized. The codebase imports the dotnet analyzers, but they may
// not be properly integrated or ecosystem detection may fail.
func TestDotNetDependenciesNotSupported(t *testing.T) {
	// Test .csproj file (C# project file)
	csprojContent := `<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <TargetFramework>net6.0</TargetFramework>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="Newtonsoft.Json" Version="13.0.1" />
    <PackageReference Include="System.Net.Http" Version="4.3.0" />
  </ItemGroup>
</Project>
`

	tempDir := t.TempDir()
	csprojFile := filepath.Join(tempDir, "Test.csproj")

	if err := os.WriteFile(csprojFile, []byte(csprojContent), 0644); err != nil {
		t.Fatalf("Failed to write .csproj file: %v", err)
	}

	// Try to analyze the .csproj file
	result, err := analyzeLibraryFile(csprojFile, []byte(csprojContent))
	if err != nil {
		t.Errorf("Failed to analyze .csproj file: %v", err)
	}

	if result == nil || len(result.Applications) == 0 {
		t.Error("Expected to find packages in .csproj analysis, but got none - .NET ecosystem may not be supported")
	}

	// Test packages.lock.json (NuGet lock file)
	nugetLockContent := `{
  "version": 1,
  "dependencies": {
    ".NETCoreApp,Version=v6.0": {
      "Newtonsoft.Json/13.0.1": {
        "type": "Direct",
        "requested": "[13.0.1, )",
        "resolved": "13.0.1"
      }
    }
  }
}
`

	nugetLockFile := filepath.Join(tempDir, "packages.lock.json")
	if err := os.WriteFile(nugetLockFile, []byte(nugetLockContent), 0644); err != nil {
		t.Fatalf("Failed to write packages.lock.json: %v", err)
	}

	result, err = analyzeLibraryFile(nugetLockFile, []byte(nugetLockContent))
	if err != nil {
		t.Errorf("Failed to analyze packages.lock.json: %v", err)
	}

	if result == nil || len(result.Applications) == 0 {
		t.Error("Expected to find packages in packages.lock.json analysis, but got none")
	}
}

// TestScanScopeIncludesNonApplicationAnalyzers tests that during library scans,
// non-application analyzers (OS packaging, secrets, licenses) are being executed
// unnecessarily, producing noise and slowing scans.
func TestScanScopeIncludesNonApplicationAnalyzers(t *testing.T) {
	// Create a minimal lockfile
	npmLockContent := `{
  "name": "test-app",
  "version": "1.0.0",
  "lockfileVersion": 2,
  "requires": true,
  "packages": {
    "": {
      "name": "test-app",
      "version": "1.0.0",
      "dependencies": {
        "lodash": "^4.17.21"
      }
    },
    "node_modules/lodash": {
      "version": "4.17.21",
      "resolved": "https://registry.npmjs.org/lodash/-/lodash-4.17.21.tgz"
    }
  }
}
`

	tempDir := t.TempDir()
