// non-application analyzers (OS packaging, secrets, licenses) are being executed
// unnecessarily, producing noise and slowing scans.
func TestScanScopeIncludesNonApplicationAnalyzers(t *testing.T) {
	// Create a minimal lockfile
	npmLockContent := `{
  "name": "test-app",
  "version": "1.0.0",
  "lockfileVersion": 2,
  "requires": true,
  "packages": {
    "": {
      "name": "test-app",
      "version": "1.0.0",
      "dependencies": {
        "lodash": "^4.17.21"
      }
    },
    "node_modules/lodash": {
      "version": "4.17.21",
      "resolved": "https://registry.npmjs.org/lodash/-/lodash-4.17.21.tgz"
    }
  }
}
`

	tempDir := t.TempDir()
	npmLockFile := filepath.Join(tempDir, "package-lock.json")

	if err := os.WriteFile(npmLockFile, []byte(npmLockContent), 0644); err != nil {
		t.Fatalf("Failed to write package-lock.json: %v", err)
	}

	// The test: Analyze and check if only language-specific analyzers are running
	// Expected: Only npm analyzer should run
	// Buggy behavior: OS analyzers, secret scanners, or license analyzers might execute
	//
	// This would manifest as:
	// - Slower analysis time than expected
	// - False positives from license/secret scanners
	// - Noise in the results

	result, err := analyzeLibraryFile(npmLockFile, []byte(npmLockContent))
	if err != nil {
		t.Errorf("Failed to analyze package-lock.json: %v", err)
	}

	if result == nil {
		t.Error("Expected analysis result, got nil")
	}

	// Check that we got npm analyzer results only
	if len(result.Applications) > 0 {
		for _, app := range result.Applications {
			// All applications should be language-specific (npm, pnpm, etc)
			if app.Type != ftypes.Npm && app.Type != ftypes.Pnpm && app.Type != ftypes.Yarn {
				t.Errorf("Got unexpected application type in library scan: %v", app.Type)
			}
		}
	}
}

