// Helper functions

// detectLockfileType detects the type of a lockfile based on its name
func detectLockfileType(filepath string) ftypes.TargetType {
	filename := extractFilename(filepath)

	switch filename {
	case "pnpm-lock.yaml":
		return ftypes.PnpmLock
	case "package-lock.json":
		return ftypes.Npm
	case "yarn.lock":
		return ftypes.Yarn
	case "packages.lock.json", "project.assets.json":
		return ftypes.NuGet
	case ".csproj", ".vbproj":
		return ftypes.DotNetCore
	default:
		return ftypes.Unknown
	}
}

// extractFilename extracts just the filename from a full path
func extractFilename(filepath string) string {
	return path_filename(filepath)
}

func path_filename(path string) string {
	for i := len(path) - 1; i >= 0; i-- {
		if path[i] == '/' || path[i] == '\\' {
			return path[i+1:]
		}
	}
	return path
}

// analyzeLibraryFile attempts to analyze a library file using Trivy's fanal analyzer
func analyzeLibraryFile(filePath string, contents []byte) (*analysisResult, error) {
	// This simulates what AnalyzeLibrary does in scanner/base.go
	// For the regression test, we'll do a simplified version that shows where issues would occur

	info, err := os.Stat(filePath)
	if err != nil {
		return nil, xerrors.Errorf("Failed to stat file: %w", err)
	}

	// Simulate analyzer initialization with language-specific analyzers only
	// In the buggy version, this might include OS analyzers, secrets, licenses, etc.

	// For now, just verify the file can be read
	data, err := os.ReadFile(filePath)
	if err != nil {
		return nil, xerrors.Errorf("Failed to read file: %w", err)
	}

	if !bytes.Equal(data, contents) {
		return nil, xerrors.New("File contents mismatch")
	}

	// Return empty result with expected structure
	// In a real scenario, this would be populated by Trivy analyzers
	return &analysisResult{
		Applications: []application{},
	}, nil
}

// Mock structures for testing
type analysisResult struct {
	Applications []application
}

type application struct {
	Type     ftypes.TargetType
	FilePath string
	Packages []packageInfo
}

type packageInfo struct {
	Name    string
	Version string
}

